   258	fn findCommandEnd(fmt: []const u8, start: usize) ?usize {
   259	    var depth: usize = 1;
   260	    var i = start;
   261	    var quote: ?u8 = null;
   262	    var escaped = false;
   263	
   264	    while (i < fmt.len) : (i += 1) {
   265	        const ch = fmt[i];
   266	        if (escaped) {
   267	            escaped = false;
   268	            continue;
   269	        }
   270	
   271	        if (ch == '\\') {
   272	            escaped = true;
   273	            continue;
   274	        }
   275	
   276	        if (quote) |q| {
   277	            if (ch == q) quote = null;
   278	            continue;
   279	        }
   280	
   281	        if (ch == '\'' or ch == '"' or ch == '`') {
   282	            quote = ch;
   283	            continue;
   284	        }
   285	
   286	        if (ch == '(') {
   287	            depth += 1;
   288	            continue;
   289	        }
   290	
   291	        if (ch == ')') {
   292	            depth -= 1;
   293	            if (depth == 0) return i;
   294	        }
   295	    }
   296	
   297	    return null;
   298	}
