   303	    var pipe_fds: [2]std.c.fd_t = undefined;
   304	    if (std.c.pipe(&pipe_fds) != 0) return error.PipeFailed;
   305	    errdefer {
   306	        _ = std.c.close(pipe_fds[0]);
   307	        _ = std.c.close(pipe_fds[1]);
   308	    }
   309	
   310	    const cmd_z = try alloc.dupeZ(u8, command);
   311	    defer alloc.free(cmd_z);
   312	
   313	    const pid = std.c.fork();
   314	    if (pid < 0) return error.ForkFailed;
   315	
   316	    if (pid == 0) {
   317	        _ = std.c.close(pipe_fds[0]);
   318	        _ = std.c.dup2(pipe_fds[1], 1);
   319	        _ = std.c.close(pipe_fds[1]);
