  1337	    fn drawLayoutBorders(
  1338	        self: *Server,
  1339	        out: *output_mod.Output,
  1340	        cell: *const @import("layout/layout.zig").LayoutCell,
  1341	        total_cols: u32,
  1342	        total_rows: u32,
  1343	        y_offset: u32,
  1344	    ) void {
  1345	        if (cell.cell_type == .pane) return;
  1346	
  1347	        const children = cell.children.items;
  1348	        if (children.len < 2) {
  1349	            for (children) |child| {
  1350	                self.drawLayoutBorders(out, child, total_cols, total_rows, y_offset);
  1351	            }
  1352	            return;
  1353	        }
  1354	
  1355	        // Draw borders between adjacent children.
  1356	        for (children[0 .. children.len - 1]) |child| {
  1357	            if (cell.cell_type == .horizontal) {
  1358	                // Vertical border: draw at (child.xoff + child.sx, child.yoff) to (child.xoff + child.sx, child.yoff + child.sy - 1)
  1359	                const bx = child.xoff + child.sx;
  1360	                const top = child.yoff;
  1361	                const bottom = @min(child.yoff + child.sy, total_rows) -| 1;
  1362	                out.attrReset();
  1363	                var y = top;
  1364	                while (y <= bottom) : (y += 1) {
  1365	                    out.cursorTo(bx, y + y_offset);
  1366	                    out.writeBytes("\xe2\x94\x82"); // U+2502 │
  1367	                }
  1368	            } else if (cell.cell_type == .vertical) {
  1369	                // Horizontal border: draw at (child.xoff, child.yoff + child.sy) to (child.xoff + child.sx - 1, child.yoff + child.sy)
  1370	                const by = child.yoff + child.sy;
  1371	                if (by >= total_rows) continue;
  1372	                const left = child.xoff;
  1373	                const right = child.xoff + child.sx -| 1;
  1374	                out.attrReset();
  1375	                out.cursorTo(left, by + y_offset);
